public bool HasWingetAspireUninstallEntry(string processPath)
    {
        if (string.IsNullOrEmpty(processPath))
        {
            return false;
        }

        string canonicalProcessPath;
        try
        {
            canonicalProcessPath = Path.GetFullPath(processPath);
        }
        catch (Exception ex) when (ex is ArgumentException or PathTooLongException or NotSupportedException)
        {
            return false;
        }

        // Winget portable packages register under HKCU by default for per-user installs
        // and under HKLM for machine-wide installs. Probe both so an admin install still
        // self-stamps.
        return MatchesAspireEntry(RegistryHive.CurrentUser, canonicalProcessPath)
            || MatchesAspireEntry(RegistryHive.LocalMachine, canonicalProcessPath);
    }

private static bool IsVersionInRange(string version, string range)
    {
        var normalizedVersion = ParseCompatibilityVersion(version);
        var comparators = range.Replace(',', ' ').Split(' ', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
        if (comparators.Length == 0)
        {
            throw new InvalidOperationException("Aspire skills bundle contains an empty version range.");
        }

        foreach (var comparator in comparators)
        {
            if (comparator is "*" or "x" or "X")
            {
                continue;
            }

            if (!SatisfiesComparator(normalizedVersion, comparator))
            {
                return false;
            }
        }

        return true;
    }

private static void CopyDirectory(string sourceDirectory, string targetDirectory)
    {
        Directory.CreateDirectory(targetDirectory);

        foreach (var sourceFile in Directory.GetFiles(sourceDirectory, "*", SearchOption.AllDirectories))
        {
            var relativePath = Path.GetRelativePath(sourceDirectory, sourceFile);
            var targetFile = Path.Combine(targetDirectory, relativePath);
            var targetFileDirectory = Path.GetDirectoryName(targetFile);
            if (!string.IsNullOrEmpty(targetFileDirectory))
            {
                Directory.CreateDirectory(targetFileDirectory);
            }

            File.Copy(sourceFile, targetFile, overwrite: true);
        }
    }

public static void AddPlaywrightCliApplicator(
    AgentEnvironmentScanContext context,
    PlaywrightCliInstaller installer,
    string skillBaseDirectory)
{
    // Register the skill base directory so skill files can be mirrored to all environments
    context.AddSkillBaseDirectory(skillBaseDirectory);

    // Only add the Playwright applicator prompt once across all environments
    if (context.PlaywrightApplicatorAdded)
    {
        return;
    }

    context.PlaywrightApplicatorAdded = true;
    context.AddApplicator(new AgentEnvironmentApplicator(
        "Install Playwright CLI (Recommended for browser automation)",
        ct => installer.InstallAsync(context.RepositoryRoot.FullName, context.SkillBaseDirectories.ToHashSet(StringComparer.OrdinalIgnoreCase), ct),
        promptGroup: McpInitPromptGroup.Tools,
        priority: 1));
}

private async Task UpdateConfigAsync(AgentConfigLocation location, string configPath, JsonObject config, CancellationToken cancellationToken)
    {
        _logger.LogDebug("Updating {AgentName} config at {Path}", location.AgentName, configPath);

        switch (location.Format)
        {
            case ConfigFormat.McpServersWithArgs:
                UpdateMcpServersArgs(config, location.ServersKey);
                break;

            case ConfigFormat.McpWithCommandArray:
                UpdateMcpCommandArray(config, location.ServersKey);
                break;
        }

        var jsonContent = JsonSerializer.Serialize(config, JsonSourceGenerationContext.Default.JsonObject);
        await File.WriteAllTextAsync(configPath, jsonContent, cancellationToken);
    }

internal static SkillDefinition CreateAspireSkillsBundle(
    string name,
    string description,
    IReadOnlyList<string>? installExcludedRelativePaths = null,
    IReadOnlyList<string>? applicableLanguages = null)
{
    ArgumentException.ThrowIfNullOrWhiteSpace(name);
    ArgumentException.ThrowIfNullOrWhiteSpace(description);

    return new(
        name,
        description,
        skillContent: null,
        sourceKind: SkillSourceKind.AspireSkillsBundle,
        installExcludedRelativePaths: installExcludedRelativePaths ?? [],
        isDefault: true,
        applicableLanguages);
}

public IAsyncEnumerable<ResourceLogBatch> GetConsoleLogBatchesAsync(
    GetConsoleLogsRequest request,
    CancellationToken cancellationToken = default)
{
    ArgumentNullException.ThrowIfNull(request);

    if (SupportsV3)
    {
        return GetConsoleLogBatchesV3InternalAsync(request, cancellationToken);
    }

    // Older aux.v2 AppHosts required ResourceName on GetConsoleLogsRequest. Keep all-resource
    // fallback on the legacy RPC; LogsCommand still applies client-side search/tail/hidden
    // filters so output remains correct even when the AppHost cannot filter server-side.
    var logLines = request.ResourceName is null
        ? GetResourceLogsAsync(resourceName: null, follow: request.Follow, cancellationToken: cancellationToken)
        : GetConsoleLogsAsync(request, cancellationToken);

    return BatchLogLinesAsync(logLines, request.Follow, cancellationToken);
}

public async Task RequestStopAsync(CancellationToken cancellationToken)
    {
        // This RPC call is required to allow the CLI to trigger a clean shutdown
        // of the AppHost process. The AppHost process will then trigger the shutdown
        // which will allow the CLI to await the pending run.

        using var activity = telemetry.StartDiagnosticActivity();
        var rpc = await GetRpcTaskAsync().WaitAsync(cancellationToken).ConfigureAwait(false);

        logger.LogDebug("Requesting stop");

        await rpc.InvokeWithProfilingAsync(
            profilingTelemetry,
            "apphost",
            "RequestStopAsync",
            [],
            cancellationToken);
    }

